db.books.aggregate([
  {
    $group: {
      _id: '$authorName',           // GROUP BY authorName
      totalBooks:  { $sum: 1 },     // COUNT(*)
      avgPrice:    { $avg: '$price' },    // AVG(price)
      minPrice:    { $min: '$price' },    // MIN(price)
      maxPrice:    { $max: '$price' },    // MAX(price)
      totalRevenue:{ $sum: '$price' },    // SUM(price)
      titles:      { $push: '$title' }    // collect into array (no SQL equiv)
    }
  },
  { $sort: { totalBooks: -1 } }
])

// SQL: SELECT authorName, COUNT(*) as cnt FROM books
//      GROUP BY authorName HAVING COUNT(*) > 2
db.books.aggregate([
  { $group:  { _id: '$authorName', cnt: { $sum: 1 } } },
  { $match:  { cnt: { $gt: 2 } } }   // HAVING — filter on grouped results
])

// SQL: SELECT b.title, a.name, a.nationality
//      FROM books b LEFT JOIN authors a ON b.authorId = a._id
db.books.aggregate([
  {
    $lookup: {
      from:         'authors',       // the collection to join
      localField:   'authorId',      // field in books
      foreignField: '_id',           // field in authors
      as:           'authorInfo'     // output array field name
    }
  },
  { $unwind: '$authorInfo' },        // flatten the single-element array
  {
    $project: {
      title: 1,
      'authorInfo.name': 1,
      'authorInfo.nationality': 1
    }
  }
])

// Include only specific fields
db.books.aggregate([
  { $project: {
    title:         1,
    price:         1,
    _id:           0,       // exclude _id
    priceWithTax:  { $multiply: ['$price', 1.1] },  // computed field
    titleUpper:    { $toUpper: '$title' }            // string expression
  }}
])

db.books.aggregate([{
  $group: {
    _id: '$authorName',
    allTitles:    { $push: '$title' },      // array with duplicates allowed
    uniqueGenres: { $addToSet: '$genres' }  // array with unique values only
  }
}])

db.books.aggregate([{
  $project: {
    title: 1,
    price: 1,
    tier: {
      $switch: {
        branches: [
          { case: { $lt: ['$price', 12] }, then: 'budget' },
          { case: { $lt: ['$price', 16] }, then: 'standard' }
        ],
        default: 'premium'   // else clause
      }
    }
  }
}])

// SQL equivalent:
// SELECT title, price,
//   CASE WHEN price < 12 THEN 'budget'
//        WHEN price < 16 THEN 'standard'
//        ELSE 'premium' END AS tier
// FROM books

db.books.aggregate([{
  $facet: {
    byGenre: [
      { $unwind: '$genres' },
      { $group: { _id: '$genres', count: { $sum: 1 } } }
    ],
    priceStats: [
      { $group: { _id: null, avg: { $avg: '$price' }, min: { $min: '$price' }, max: { $max: '$price' } } }
    ],
    topRated: [
      { $sort: { rating: -1 } },
      { $limit: 3 },
      { $project: { title: 1, rating: 1, _id: 0 } }
    ]
  }
}])
// Returns ONE document with three arrays: byGenre, priceStats, topRated

db.books.aggregate([
  { $group: { _id: '$authorName', bookCount: { $sum: 1 }, avgRating: { $avg: '$rating' } } },
  { $sort: { bookCount: -1 } },
  { $out: 'author_stats' }   // saves results into the 'author_stats' collection
])
// WARNING: replaces author_stats entirely if it exists

db.authors.aggregate([{
  $lookup: {
    from: 'books',
    let: { authorId: '$_id' },
    pipeline: [
      { $match: { $expr: { $eq: ['$authorId', '$$authorId'] } } },
      { $match: { inStock: true } },   // additional filter on joined collection
      { $project: { title: 1, price: 1, _id: 0 } }
    ],
    as: 'inStockBooks'
  }
}])
// Returns each author with only their in-stock books
